import csv
import os
from collections import defaultdict
import math

# Parse service reports
def parse_service_reports():
    events = []
    base = '/app/raw_service_reports'
    for day_dir in sorted(os.listdir(base)):
        day_path = os.path.join(base, day_dir)
        if not os.path.isdir(day_path):
            continue
        for fname in sorted(os.listdir(day_path)):
            fpath = os.path.join(day_path, fname)
            with open(fpath) as f:
                content = f.read()
            data = {}
            for line in content.strip().splitlines():
                if ':' in line:
                    k, _, v = line.partition(':')
                    data[k.strip()] = v.strip()
            wo = data.get('WORK ORDER', '')
            machine = data.get('MACHINE', '')
            tech = data.get('TECHNICIAN', '')
            day = int(data.get('DAY', 0))
            completed_str = data.get('COMPLETED', '')
            if completed_str and ':' in completed_str:
                h, m = completed_str.split(':')
                completed_min = int(h) * 60 + int(m)
            else:
                completed_min = 0
            started_str = data.get('STARTED', '')
            if started_str and ':' in started_str:
                h, m = started_str.split(':')
                started_min = int(h) * 60 + int(m)
            else:
                started_min = 0
            events.append({
                'work_order_id': wo,
                'machine_id': machine,
                'technician_id': tech,
                'day': day,
                'started_min': started_min,
                'completed_min': completed_min,
            })
    return events

def time_to_min(t):
    h, m = t.split(':')
    return int(h)*60 + int(m)

service_events = parse_service_reports()

# Load machine assignment log
mal = {}
with open('/app/machine_assignment_log.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        mal[row['job_id']] = {
            'day': int(row['day']),
            'machine_id': row['machine_id'],
            'start_min': time_to_min(row['start_time']),
        }

# Load production batches
batches = []
with open('/app/production_batches.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        job_id = row['job_id']
        job_info = mal.get(job_id, {})
        batches.append({
            'batch_id': row['batch_id'],
            'job_id': job_id,
            'machine_id': row['machine_id'],
            'product_id': row['product_id'],
            'production_day': int(row['production_day']),
            'start_min': job_info.get('start_min', 0),
        })

# Load quality inspections
inspections = {}
with open('/app/quality_inspections.csv') as f:
    reader = csv.DictReader(f)
    for row in reader:
        inspections[row['batch_id']] = row['inspection_result']

# Build maintenance timeline per machine (sorted by day, then completed time)
machine_maintenance = defaultdict(list)
for ev in service_events:
    machine_maintenance[ev['machine_id']].append(ev)

for mid in machine_maintenance:
    machine_maintenance[mid].sort(key=lambda x: (x['day'], x['completed_min']))

# For each maintenance window, compute batches in window and rejection count
# A window is defined by: maintenance event E_i to next maintenance E_{i+1}
# Batches in window: batch is on same machine, and batch (day, start_min) > (E_i.day, E_i.completed_min)
# and (day, start_min) <= (E_{i+1}.day, E_{i+1}.completed_min) or no E_{i+1}

# For each machine, pair each maintenance event with its subsequent window
machine_windows = {}  # (machine_id, event_idx) -> {event, batches: []}
for machine_id, events in machine_maintenance.items():
    machine_windows[machine_id] = []
    for i, ev in enumerate(events):
        next_ev = events[i+1] if i+1 < len(events) else None
        machine_windows[machine_id].append({
            'event': ev,
            'next_event': next_ev,
            'batches': [],
            'rejected': [],
        })

# Assign batches to windows
for batch in batches:
    mid = batch['machine_id']
    if mid not in machine_windows:
        continue
    windows = machine_windows[mid]

    # Binary search for the right window
    # Find window where event (day, completed_min) <= batch (day, start_min) < next event
    batch_time = (batch['production_day'], batch['start_min'])

    assigned_window = None
    for i, win in enumerate(windows):
        ev = win['event']
        ev_time = (ev['day'], ev['completed_min'])

        if batch_time >= ev_time:
            if win['next_event'] is None:
                assigned_window = i
            else:
                nev = win['next_event']
                nev_time = (nev['day'], nev['completed_min'])
                if batch_time < nev_time:
                    assigned_window = i

    if assigned_window is not None:
        win = machine_windows[mid][assigned_window]
        win['batches'].append(batch['batch_id'])
        if inspections.get(batch['batch_id']) == 'REJECTED':
            win['rejected'].append(batch['batch_id'])

# Compute window statistics
all_window_stats = []
for machine_id, windows in machine_windows.items():
    for win in windows:
        n = len(win['batches'])
        r = len(win['rejected'])
        all_window_stats.append({
            'machine_id': machine_id,
            'event': win['event'],
            'n_batches': n,
            'n_rejected': r,
            'rejection_rate': r/n if n > 0 else 0,
            'rejected_batches': win['rejected'],
        })

# Distribution of rejections per window
rej_counts = defaultdict(int)
for ws in all_window_stats:
    rej_counts[ws['n_rejected']] += 1

print("Distribution of rejected batches per maintenance window:")
for k in sorted(rej_counts.keys())[:15]:
    print(f"  {k} rejections: {rej_counts[k]} windows")

# Find windows with most rejections
top_windows = sorted(all_window_stats, key=lambda x: -x['n_rejected'])[:20]
print("\nTop 20 windows by rejection count:")
for ws in top_windows:
    ev = ws['event']
    print(f"  Machine {ws['machine_id']}, WO {ev['work_order_id']}, Tech {ev['technician_id']}, "
          f"Day {ev['day']}, Batches: {ws['n_batches']}, Rejected: {ws['n_rejected']}, "
          f"Rate: {ws['rejection_rate']:.3f}")
EOF

