                       'start_min': ji.get('start_min', 0)})

inspections = {}
with open('/app/quality_inspections.csv') as f:
    for row in csv.DictReader(f):
        inspections[row['batch_id']] = row['inspection_result']

product_total = defaultdict(int)
product_rejected = defaultdict(int)
for b in batches:
    product_total[b['product_id']] += 1
    if inspections.get(b['batch_id']) == 'REJECTED':
        product_rejected[b['product_id']] += 1
product_baseline = {p: product_rejected[p]/product_total[p] for p in product_total}

machine_maintenance = defaultdict(list)
for ev in service_events:
    machine_maintenance[ev['machine_id']].append(ev)
for mid in machine_maintenance:
    machine_maintenance[mid].sort(key=lambda x: (x['day'], x['completed_min']))

machine_windows = {}
for machine_id, events in machine_maintenance.items():
    machine_windows[machine_id] = []
    for i, ev in enumerate(events):
        next_ev = events[i+1] if i+1 < len(events) else None
        machine_windows[machine_id].append({
            'event': ev, 'next_event': next_ev, 'batches': [], 'rejected_batches': []
        })

for batch in batches:
    mid = batch['machine_id']
    if mid not in machine_windows:
        continue
    batch_time = (batch['production_day'], batch['start_min'])
    assigned = None
    for i, win in enumerate(machine_windows[mid]):
        ev_time = (win['event']['day'], win['event']['completed_min'])
        if batch_time >= ev_time:
            if win['next_event'] is None:
                assigned = i
            else:
                nev_time = (win['next_event']['day'], win['next_event']['completed_min'])
                if batch_time < nev_time:
                    assigned = i
    if assigned is not None:
        win = machine_windows[mid][assigned]
        win['batches'].append(batch)
        if inspections.get(batch['batch_id']) == 'REJECTED':
            win['rejected_batches'].append(batch)

# Collect all significant window-product pairs with their stats
all_pairs = []
for machine_id, windows in machine_windows.items():
    for win in windows:
        if not win['rejected_batches']:
            continue
        ev = win['event']
        prod_batches = defaultdict(list)
        prod_rejected = defaultdict(list)
        for b in win['batches']:
            prod_batches[b['product_id']].append(b)
        for b in win['rejected_batches']:
            prod_rejected[b['product_id']].append(b)
        for product_id, rej_list in prod_rejected.items():
            n = len(prod_batches[product_id])
            k = len(rej_list)
            p_baseline = product_baseline.get(product_id, 0.01)
            pval = binom_pvalue(k, n, p_baseline)
            rate_in_window = k/n
            all_pairs.append({
                'machine_id': machine_id,
                'technician_id': ev['technician_id'],
                'work_order_id': ev['work_order_id'],
                'product_id': product_id,
                'n': n, 'k': k,
                'rate': rate_in_window,
                'baseline': p_baseline,
                'fold_change': rate_in_window / p_baseline,
                'pval': pval,
                'batches': rej_list,
            })

# Test different thresholds
for threshold in [0.05, 0.01, 0.001]:
    print(f"\n=== THRESHOLD p < {threshold} ===")
    confirmed_techs = set()
    tech_batches = defaultdict(list)
    tech_work_orders = defaultdict(set)

    for pair in all_pairs:
        if pair['pval'] < threshold:
            tech = pair['technician_id']
            for b in pair['batches']:
                tech_batches[tech].append({'batch_id': b['batch_id'], 'product_id': pair['product_id'],
                                           'work_order_id': pair['work_order_id']})
            tech_work_orders[tech].add(pair['work_order_id'])

    for tech in sorted(tech_batches.keys()):
        n_b = len(tech_batches[tech])
        n_wo = len(tech_work_orders[tech])
        if n_b >= 3 and n_wo >= 2:
            confirmed_techs.add(tech)

    print(f"Confirmed technicians ({len(confirmed_techs)}): {sorted(confirmed_techs)}")

    # Products
    product_to_techs = defaultdict(set)
    for pair in all_pairs:
        if pair['pval'] < threshold and pair['technician_id'] in confirmed_techs:
            product_to_techs[pair['product_id']].add(pair['technician_id'])

    for prod in sorted(product_to_techs.keys()):
        print(f"  {prod}: {sorted(product_to_techs[prod])}")

# Show borderline pairs (0.01 < p < 0.05)
print("\n=== Borderline pairs (0.01 < p < 0.05) ===")
borderline = [(p['technician_id'], p['work_order_id'], p['product_id'], 
               p['n'], p['k'], p['rate'], p['baseline'], p['fold_change'], p['pval'])
              for p in all_pairs if 0.01 <= p['pval'] < 0.05]
borderline.sort(key=lambda x: x[0])
for tech, wo, prod, n, k, rate, base, fold, pval in borderline:
    print(f"  {tech}, {wo}, {prod}: {k}/{n} ({rate:.0%} vs {base:.1%} baseline, {fold:.1f}x fold, p={pval:.4f})")
