"""
Analysis approach:
1. For each (technician, product) pair, collect ALL batches of that product
   produced in maintenance windows following that technician's work.
2. Test if the rejection rate in those windows is significantly elevated
   vs. product baseline, using a binomial test.
3. If a technician shows significantly elevated rejection rates for a product,
   they may be responsible for maintenance-caused quality issues on that product.
4. Apply confirmation criteria: >= 3 rejected batches across >= 2 work orders.
5. For confirmed technicians, list all affected products.

This approach avoids per-window multiple testing issues by aggregating across
all work orders for each (tech, product) pair.
"""

import csv
import os
import json
from collections import defaultdict

def parse_service_reports():
    events = []
    base = '/app/raw_service_reports'
    for day_dir in sorted(os.listdir(base)):
        day_path = os.path.join(base, day_dir)
        if not os.path.isdir(day_path):
            continue
        for fname in sorted(os.listdir(day_path)):
            fpath = os.path.join(day_path, fname)
            with open(fpath) as f:
                content = f.read()
            data = {}
            for line in content.strip().splitlines():
                if ':' in line:
                    k, _, v = line.partition(':')
                    data[k.strip()] = v.strip()
            completed_str = data.get('COMPLETED', '')
            h, m = completed_str.split(':')
            events.append({
                'work_order_id': data.get('WORK ORDER', ''),
                'machine_id': data.get('MACHINE', ''),
                'technician_id': data.get('TECHNICIAN', ''),
                'day': int(data.get('DAY', 0)),
                'completed_min': int(h)*60 + int(m),
            })
    return events

def time_to_min(t):
    h, m = t.split(':')
    return int(h)*60 + int(m)

def binom_pvalue(k, n, p):
    """P(X >= k | Binomial(n, p)) - one-sided p-value for elevated rate"""
    if k <= 0:
        return 1.0
    result = 0.0
    coeff = 1.0
    for i in range(n+1):
        if i > 0:
            coeff *= (n - i + 1) / i
        term = coeff * (p**i) * ((1-p)**(n-i))
        if i >= k:
            result += term
    return min(result, 1.0)

print("Loading data...")
service_events = parse_service_reports()

mal = {}
with open('/app/machine_assignment_log.csv') as f:
    for row in csv.DictReader(f):
        mal[row['job_id']] = {
            'day': int(row['day']),
            'machine_id': row['machine_id'],
            'start_min': time_to_min(row['start_time'])
        }

batches = []
with open('/app/production_batches.csv') as f:
    for row in csv.DictReader(f):
        ji = mal.get(row['job_id'], {})
        batches.append({
            'batch_id': row['batch_id'],
            'machine_id': row['machine_id'],
            'product_id': row['product_id'],
            'production_day': int(row['production_day']),
            'start_min': ji.get('start_min', 0)
        })

inspections = {}
with open('/app/quality_inspections.csv') as f:
    for row in csv.DictReader(f):
        inspections[row['batch_id']] = row['inspection_result']

# Product baseline rejection rates
product_total = defaultdict(int)
product_rejected = defaultdict(int)
for b in batches:
    product_total[b['product_id']] += 1
    if inspections.get(b['batch_id']) == 'REJECTED':
        product_rejected[b['product_id']] += 1
product_baseline = {p: product_rejected[p]/product_total[p] for p in product_total}

# Build maintenance timeline per machine
machine_maintenance = defaultdict(list)
for ev in service_events:
    machine_maintenance[ev['machine_id']].append(ev)
for mid in machine_maintenance:
    machine_maintenance[mid].sort(key=lambda x: (x['day'], x['completed_min']))

# Build windows and assign batches with precise timing
machine_windows = {}
for machine_id, events in machine_maintenance.items():
    machine_windows[machine_id] = []
    for i, ev in enumerate(events):
        next_ev = events[i+1] if i+1 < len(events) else None
        machine_windows[machine_id].append({
            'event': ev, 'next_event': next_ev, 'batches': [], 'rejected_batches': []
        })

for batch in batches:
    mid = batch['machine_id']
    if mid not in machine_windows:
        continue
    batch_time = (batch['production_day'], batch['start_min'])
    assigned = None
    for i, win in enumerate(machine_windows[mid]):
        ev_time = (win['event']['day'], win['event']['completed_min'])
        if batch_time >= ev_time:
            if win['next_event'] is None:
                assigned = i
            else:
                nev_time = (win['next_event']['day'], win['next_event']['completed_min'])
                if batch_time < nev_time:
                    assigned = i
    if assigned is not None:
        win = machine_windows[mid][assigned]
        win['batches'].append(batch)
        if inspections.get(batch['batch_id']) == 'REJECTED':
            win['rejected_batches'].append(batch)

# For each (technician, product) pair, aggregate stats across all their work orders
# For each rejected batch in a window, track which (tech, product, work_order) it belongs to

# Structure: (tech, product) -> {'total_n': int, 'total_k': int, 'rejected_batches_by_wo': {wo: [batch_ids]}}
tech_product_stats = defaultdict(lambda: {'total_n': 0, 'total_k': 0, 'rejected_by_wo': defaultdict(list)})

for machine_id, windows in machine_windows.items():
    for win in windows:
        ev = win['event']
        tech = ev['technician_id']
        wo = ev['work_order_id']

        # Count batches per product in this window
        prod_n = defaultdict(int)
        for b in win['batches']:
            prod_n[b['product_id']] += 1

        # Count rejected batches per product in this window
        prod_k = defaultdict(list)
        for b in win['rejected_batches']:
            prod_k[b['product_id']].append(b['batch_id'])

        # Add to tech-product stats
        for product_id in prod_n:
            key = (tech, product_id)
            tech_product_stats[key]['total_n'] += prod_n[product_id]
            if product_id in prod_k:
                tech_product_stats[key]['total_k'] += len(prod_k[product_id])
                tech_product_stats[key]['rejected_by_wo'][wo].extend(prod_k[product_id])

# For each (tech, product) pair, compute p-value
# A pair is "significant" if the overall rejection rate for that tech's windows is elevated
TECH_PRODUCT_PVALUE_THRESHOLD = 0.01  # stricter threshold at aggregated level

significant_pairs = []  # (tech, product, total_n, total_k, p_val)
for (tech, product), stats in tech_product_stats.items():
    n = stats['total_n']
    k = stats['total_k']
    if k == 0:
        continue
    baseline = product_baseline.get(product, 0.01)
    pval = binom_pvalue(k, n, baseline)
    if pval < TECH_PRODUCT_PVALUE_THRESHOLD:
        significant_pairs.append({
            'technician_id': tech,
            'product_id': product,
            'total_n': n,
            'total_k': k,
            'baseline': baseline,
            'fold_change': (k/n)/baseline,
            'pval': pval,
            'rejected_by_wo': dict(stats['rejected_by_wo']),
        })

print(f"\nSignificant (tech, product) pairs at p<{TECH_PRODUCT_PVALUE_THRESHOLD}: {len(significant_pairs)}")

# Now apply confirmation criteria:
# Tech is confirmed if they have >= 3 rejected batches across >= 2 DISTINCT work orders
# (across all their significant product pairs combined)

# For each confirmed pair, check work orders
tech_total_rejected = defaultdict(list)  # tech -> list of (batch_id, wo, product)
tech_significant_products = defaultdict(set)

for pair in significant_pairs:
    tech = pair['technician_id']
    product = pair['product_id']
    for wo, batch_ids in pair['rejected_by_wo'].items():
        for bid in batch_ids:
            tech_total_rejected[tech].append({
                'batch_id': bid,
                'work_order_id': wo,
                'product_id': product
            })
    tech_significant_products[tech].add(product)

# Confirmation: >= 3 distinct rejected batches across >= 2 distinct work orders
confirmed_techs = set()
tech_summary = {}
for tech, records in tech_total_rejected.items():
    n_batches = len(records)
    n_wos = len(set(r['work_order_id'] for r in records))
    tech_summary[tech] = {'n_batches': n_batches, 'n_wos': n_wos}
    if n_batches >= 3 and n_wos >= 2:
        confirmed_techs.add(tech)

print("\n--- Technician Summary (significant at tech-product level) ---")
for tech in sorted(tech_summary.keys()):
    s = tech_summary[tech]
    status = "CONFIRMED" if tech in confirmed_techs else "NOT CONFIRMED"
    print(f"  {tech}: {s['n_batches']} batches, {s['n_wos']} WOs - {status}")

print(f"\nTotal confirmed technicians: {len(confirmed_techs)}")

# For confirmed technicians, list affected products
# A product is included if the (tech, product) pair is significant AND the tech is confirmed
product_to_techs = defaultdict(set)
for pair in significant_pairs:
    tech = pair['technician_id']
    if tech in confirmed_techs:
        product_to_techs[pair['product_id']].add(tech)

# Build answer
answer = {}
for product_id in sorted(product_to_techs.keys()):
    techs = sorted(product_to_techs[product_id])
    answer[product_id] = techs

print("\n=== ANSWER ===")
print(json.dumps(answer, indent=2))

# Detailed view per confirmed tech
print("\n--- Detailed confirmed tech analysis ---")
for tech in sorted(confirmed_techs):
    s = tech_summary[tech]
    print(f"\n{tech}: {s['n_batches']} batches, {s['n_wos']} WOs")
    # Show per-product pair stats
    tech_pairs = [p for p in significant_pairs if p['technician_id'] == tech]
    for pair in sorted(tech_pairs, key=lambda x: x['pval']):
        wos = list(pair['rejected_by_wo'].keys())
        total_k = pair['total_k']
        total_n = pair['total_n']
        print(f"  Product {pair['product_id']}: {total_k}/{total_n} ({total_k/total_n:.0%}) "
              f"vs {pair['baseline']:.2%} baseline, {pair['fold_change']:.1f}x fold, "
              f"p={pair['pval']:.6f}, WOs: {wos}")

with open('/app/answer.json', 'w') as f:
    json.dump(answer, f, indent=2)
print("\nSaved to /app/answer.json")

