                       'product_id': row['product_id'], 'production_day': int(row['production_day']),
                       'start_min': ji.get('start_min', 0)})

inspections = {}
with open('/app/quality_inspections.csv') as f:
    for row in csv.DictReader(f):
        inspections[row['batch_id']] = row['inspection_result']

product_total = defaultdict(int)
product_rejected = defaultdict(int)
for b in batches:
    product_total[b['product_id']] += 1
    if inspections.get(b['batch_id']) == 'REJECTED':
        product_rejected[b['product_id']] += 1
product_baseline = {p: product_rejected[p]/product_total[p] for p in product_total}

machine_maintenance = defaultdict(list)
for ev in service_events:
    machine_maintenance[ev['machine_id']].append(ev)
for mid in machine_maintenance:
    machine_maintenance[mid].sort(key=lambda x: (x['day'], x['completed_min']))

machine_windows = {}
for machine_id, events in machine_maintenance.items():
    machine_windows[machine_id] = []
    for i, ev in enumerate(events):
        next_ev = events[i+1] if i+1 < len(events) else None
        machine_windows[machine_id].append({'event': ev, 'next_event': next_ev, 'batches': [], 'rejected_batches': []})

for batch in batches:
    mid = batch['machine_id']
    if mid not in machine_windows: continue
    batch_time = (batch['production_day'], batch['start_min'])
    assigned = None
    for i, win in enumerate(machine_windows[mid]):
        ev_time = (win['event']['day'], win['event']['completed_min'])
        if batch_time >= ev_time:
            if win['next_event'] is None:
                assigned = i
            else:
                nev_time = (win['next_event']['day'], win['next_event']['completed_min'])
                if batch_time < nev_time:
                    assigned = i
    if assigned is not None:
        win = machine_windows[mid][assigned]
        win['batches'].append(batch)
        if inspections.get(batch['batch_id']) == 'REJECTED':
            win['rejected_batches'].append(batch)

# Per-window binomial test with p < 0.01
THRESHOLD = 0.01
maintenance_caused = []  # {batch_id, product_id, tech_id, work_order_id, pval, n, k}

for machine_id, windows in machine_windows.items():
    for win in windows:
        if not win['rejected_batches']: continue
        ev = win['event']
        prod_batches = defaultdict(list)
        prod_rejected = defaultdict(list)
        for b in win['batches']: prod_batches[b['product_id']].append(b)
        for b in win['rejected_batches']: prod_rejected[b['product_id']].append(b)
        for product_id, rej_list in prod_rejected.items():
            n = len(prod_batches[product_id])
            k = len(rej_list)
            p_baseline = product_baseline.get(product_id, 0.01)
            pval = binom_pvalue(k, n, p_baseline)
            if pval < THRESHOLD:
                for b in rej_list:
                    maintenance_caused.append({
                        'batch_id': b['batch_id'], 'product_id': product_id,
                        'machine_id': machine_id, 'technician_id': ev['technician_id'],
                        'work_order_id': ev['work_order_id'], 'pval': pval, 'n': n, 'k': k
                    })

# Count per technician
tech_batches = defaultdict(list)
tech_work_orders = defaultdict(set)
for rec in maintenance_caused:
    tech = rec['technician_id']
    tech_batches[tech].append(rec)
    tech_work_orders[tech].add(rec['work_order_id'])

# Confirm technicians
confirmed_techs = set()
for tech, recs in tech_batches.items():
    n_b = len(recs)
    n_wo = len(tech_work_orders[tech])
    if n_b >= 3 and n_wo >= 2:
        confirmed_techs.add(tech)

print(f"Confirmed technicians ({len(confirmed_techs)}): {sorted(confirmed_techs)}")
print()

# Detailed breakdown per confirmed tech
for tech in sorted(confirmed_techs):
    n_b = len(tech_batches[tech])
    n_wo = len(tech_work_orders[tech])
    print(f"{tech}: {n_b} batches, {n_wo} WOs")
    # Show per WO details
    wo_prod = defaultdict(lambda: defaultdict(list))
    for rec in tech_batches[tech]:
        wo_prod[rec['work_order_id']][rec['product_id']].append(rec)
    for wo, prods in sorted(wo_prod.items()):
        for prod, recs in sorted(prods.items()):
            r = recs[0]
            print(f"  {wo}, {prod}: {r['k']}/{r['n']} (p={r['pval']:.6f}), {len(recs)} batches")
    print()

# Products for confirmed techs
product_to_techs = defaultdict(set)
for rec in maintenance_caused:
    if rec['technician_id'] in confirmed_techs:
        product_to_techs[rec['product_id']].add(rec['technician_id'])

answer = {p: sorted(t) for p, t in sorted(product_to_techs.items())}
print("=== FINAL ANSWER ===")
print(json.dumps(answer, indent=2))

with open('/app/answer.json', 'w') as f:
    json.dump(answer, f, indent=2)
print("\nSaved to /app/answer.json")
EOF
